#include <bits/stdc++.h>
using namespace std;
int k,n,m,sum[1003],ans,mark[1003],p[1003];
vector<int> g[1003];
void bfs(int x,int num){
    queue<int> q;
    q.push(x),mark[x]=num,sum[x]++;
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        for(int i=0;i<len;i++)
            if(mark[g[f][i]]!=num)
                mark[g[f][i]]=num,sum[g[f][i]]++,q.push(g[f][i]);
    }
}
int main(){
    scanf("%d%d%d",&k,&n,&m);
    for(int i=1;i<=k;i++)
        scanf("%d",&p[i]);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
    }
    for(int i=1;i<=k;i++)
        bfs(p[i],i);
    for(int i=1;i<=n;i++)
        if(sum[i]==k)
            ans++;
    printf("%d",ans);
    return 0;
}
